'use strict';

const { fork } = require('child_process');
const { hello } = require('../types');

// Mirrors jest-worker's BaseWorkerPool.end(): the worker gets an END message and this
// long to exit gracefully before it is force-killed by SIGTERM (losing its exit hooks).
// jest-worker hardcodes 500ms; env-overridable so kill-path tests (which wait out the
// full delay in real time) can shorten it -- the kill semantics are delay-independent
// once the call round-trip has completed. STASIS_TEST_-prefixed (the repo's test-plumbing
// convention) and `||` (not `??`) so an ambient empty/unset value can't zero the delay.
const FORCE_EXIT_DELAY = Number(process.env.STASIS_TEST_FORCE_EXIT_DELAY || 500);

// The SIGTERM -> SIGKILL escalation window. jest-worker reuses FORCE_EXIT_DELAY for it, but
// here it is deliberately DECOUPLED and generous, because tying the two together makes the
// kill-path test flaky: it shortens FORCE_EXIT_DELAY to keep the END->SIGTERM wait cheap,
// and a SIGKILL that lands that soon after SIGTERM is a false-failure hazard. The loader's
// SIGTERM shard-flush handler (a synchronous save() plus a re-delivered SIGTERM) has to
// finish inside this window; under CI contention a few dozen ms is not enough, so the worker
// dies by SIGKILL and the signal=SIGTERM assertion (and the very shard the flush exists to
// save) flakes. A cleanly-flushing worker NEVER waits this out -- it dies by the re-delivered
// SIGTERM and the parent's 'exit' listener clears the timer below -- so a wide window costs a
// passing test nothing; it only bounds how long a GENUINELY broken flush hangs (HOLD_HANDLE
// pins the loop) before it surfaces as an observable signal=SIGKILL. Hence a large default,
// still env-overridable for anyone probing the escalation itself.
const SIGKILL_DELAY = Number(process.env.STASIS_TEST_SIGKILL_DELAY || 5000);

// Mirrors jest-worker's ChildProcessWorker: the parent process NEVER require()s
// ./processChild -- it only require.resolve()s it and forks the resolved path, so the
// file's bytes are loaded exclusively in the forked child, as that child's entry.
class ChildProcessWorker {
  constructor() {
    this._child = fork(require.resolve('./processChild'), [], {
      // jest-worker filters only --debug/--inspect, keeping e.g. --import intact.
      execArgv: process.execArgv.filter((v) => !/^--(debug|inspect)/.test(v)),
    });
  }

  call(input) {
    return new Promise((resolve, reject) => {
      this._child.once('message', (msg) => {
        if (msg[0] === 'ok') resolve(msg[1]);
        else reject(new Error(`worker error: ${msg[1]}`));
      });
      this._child.send(['call', input]);
    });
  }

  end() {
    return new Promise((resolve) => {
      // SIGTERM after FORCE_EXIT_DELAY, then SIGKILL after SIGKILL_DELAY -- the same
      // escalation real jest-worker's forceExit performs (it reuses one delay for both; we
      // split them so the SIGKILL window can be generous -- see SIGKILL_DELAY). The SIGKILL
      // mirror matters for the tests: if the loader's flush handler ever stops re-delivering
      // SIGTERM, the worker would otherwise survive forever (HOLD_HANDLE pins its loop) and
      // the suite would HANG instead of failing the signal=SIGTERM assertion with an
      // observable signal=SIGKILL.
      let sigkillTimeout;
      const forceExitTimeout = setTimeout(() => {
        this._child.kill('SIGTERM');
        sigkillTimeout = setTimeout(() => {
          this._child.kill('SIGKILL');
        }, SIGKILL_DELAY);
      }, FORCE_EXIT_DELAY);
      this._child.once('exit', (code, signal) => {
        clearTimeout(forceExitTimeout);
        clearTimeout(sigkillTimeout);
        // `hello` keeps the PARENT-side require('../types') load -- real jest-worker's
        // ChildProcessWorker requires ../types too, which is what puts the shared types.js
        // in the main process's capture alongside the child's.
        console.log(`PARENT worker-exit code=${code} signal=${signal} types=${hello}`);
        resolve();
      });
      this._child.send(['end']);
    });
  }
}

module.exports = { ChildProcessWorker };
